insert into products(title,price,image,category,description,active,sort_order) values('Chanel Style',0,base||'chanel-style.jpeg','Locacao','Painel de fundo arredondado branco texturizado. Arco organico de baloes brancos foscos e baloes pretos metalizados com lacos de fita pretos. Letreiro de neon Happy Birthday. 3 Cilindros brancos texturizados. 1 Laco de tecido preto no topo. 1 Vaso alto de cristal com arranjo floral misto. 1 Tapete felpudo cinza escuro. 1 Suporte aramado de metal preto para doces. 3 Suportes brancos e pretos para doces.',true,1) returning id into p1;
insert into products(title,price,image,category,description,active,sort_order) values('Classic Pink & Cristal',0,base||'classic-pink-cristal.png','Locacao','Painel de fundo arredondado rosa seco (dusty rose). Arco organico rosa chiclete e branco. Letreiro de neon Happy Birthday. 3 Mesas cilindricas com base aramada dourada. 1 Suporte alto aramado dourado. 2 Vasos de cristal com arranjos de rosas rosa e lilas. Arranjo floral de chao. Kit de baloes metalizados ouro rose. 1 Tapete felpudo rosa claro. 1 Suporte de bolo aramado dourado rose.',true,2) returning id into p2;
insert into products(title,price,image,category,description,active,sort_order) values('Decoracao de 15 Anos Classica Roxo e Prata',0,base||'15-anos-classica-roxo-prata.jpeg','Temas Personalizados','Painel de baloes em espiral roxo e prata, cortina metalica roxa. Mesa retangular com tampo preto, duas mesas cilindricas roxo e branco. Dois vasos brancos com plantas artificiais, dois vasos com flores roxas/rosa, dois suportes pretos para bolo, tres suportes para doces. Baloes numeros 1 e 5 em prata.',true,3) returning id into p3;
insert into products(title,price,image,category,description,active,sort_order) values('Decoracao de 15 Anos Glamourosa Roxo e Ouro',0,base||'15-anos-glamourosa-roxo-ouro.jpeg','Temas Personalizados','Painel de baloes em espiral roxo e lavanda, painel de fundo roxo com nome e idade 15 Anos em branco. Tres mesas cilindricas roxo e lavanda, duas mesas com bases douradas e tampos de vidro. Dois suportes para bolo lavanda, tres vasos com flores artificiais, duas bandejas lavanda, cesta com plantas. Painel circular com borboleta azul. Neon numerico 15.',true,4) returning id into p4;
insert into products(title,price,image,category,description,active,sort_order) values('Decoracao de Aniversario Tropical e Colorida',0,base||'aniversario-tropical-colorida.png','Temas Personalizados','Painel de baloes organicos rosa, laranja e creme, painel de fundo azul com Happy Birthday dourado. Quatro mesas com base de madeira ripada, duas mesinhas com tampo dourado, duas bases para bolo aramadas. Dois vasos de flores artificiais, tres bandejas cor-de-rosa, suporte para doces dourado, baloes metalicos. Neon numerico 15.',true,5) returning id into p5;
insert into products(title,price,image,category,description,active,sort_order) values('Decoracao Elegancia Verde Esmeralda e Dourado',0,base||'elegancia-verde-esmeralda-dourado.jpeg','Locacao','Tres cilindros vazados, um arco redondo vazado, 1 tapete cinza, 1 jarro de flor, 1 boleira, kit de balao desconstruido em verde limao, bandeira e dourado, painel quadrado com cortinas verde e voal branco.',true,6) returning id into p6;
insert into products(title,price,image,category,description,active,sort_order) values('Decoracao Natural Boho',0,base||'natural-boho.jpeg','Locacao','Painel de fundo arredondado cinza-taupe e painel verde-oliva fosco. Arco organico verde-musgo, creme, pessego palido e baloes metalizados dourados com bubble. Letreiro de neon Happy Birthday. 3 Mesas de madeira ripada rustica (P, M, G). Kit de baloes metalizados dourados com numero. 1 Tapete felpudo bege.',true,7) returning id into p7;
insert into products(title,price,image,category,description,active,sort_order) values('Deep Blue & Gold',0,base||'deep-blue-gold.jpeg','Locacao','Painel de fundo arredondado azul royal texturizado (veludo molhado). Arco organico azul royal e prata metalizado. Letreiro de neon Happy Birthday. 3 Mesas de base ripada de madeira (P, M, G). 2 Vasos altos com arranjo floral rustico. 1 Tapete felpudo azul royal. 3 Suportes dourados com pe. 1 Boleira aramada dourada.',true,8) returning id into p8;
insert into products(title,price,image,category,description,active,sort_order) values('Earthly Gold',0,base||'earthly-gold.jpeg','Locacao','Painel de fundo arredondado rosa terracota. Arco organico terracota, creme, ouro cromado e bubble. Letreiro de neon Happy Birthday. 3 Mesas de base geometrica aramada preta (P, M, G). 2 Vasos altos de cristal com arranjo floral misto. 1 Tapete bege texturizado. 2 Suportes aramados metal preto para doces. 2 Boleiras metal preto.',true,9) returning id into p9;
insert into products(title,price,image,category,description,active,sort_order) values('Elegancia Black & Gold',0,base||'elegancia-black-gold.jpeg','Locacao','Painel de fundo preto texturizado. Arco organico baloes pretos foscos e dourados cromados. Letreiro de neon Happy Birthday. 1 Mesa de cubo dourada com espelho. 1 Mesa de cubo dourada aramada vazada. 1 Cilindro preto grande. 1 Boleira aramada dourada. 2 Suportes dourados para doces. 1 Bandeja dourada. 1 Tapete cinza escuro. 1 Vaso aramado dourado com buxinho verde.',true,10) returning id into p10;
insert into products(title,price,image,category,description,active,sort_order) values('Fortune Tiger',0,base||'fortune-tiger.jpeg','Temas Personalizados','1 Painel retangular laranja vibrante sublimado. 1 Painel redondo sublimado com Fortune Tiger. Arco organico laranja, amarelo e dourado. 3 Cilindros sublimados tematicos (P, M, G). 1 Mesa de cubo laranja vazada. 2 Vasos de ceramica brancos com arranjo floral. 1 Suporte de bolo laranja. 1 Boleira dourada. 1 Suporte branco para doces. 1 Tapete de grama sintetica verde.',true,11) returning id into p11;
insert into products(title,price,image,category,description,active,sort_order) values('Golden & Sunflower',0,base||'golden-sunflower.jpeg','Locacao','Painel de fundo arredondado branco texturizado. Arco organico dourado cromado e branco fosco. Letreiro de neon Happy Birthday. 3 Mesas base geometrica aramada dourada (P, M, G). 2 Suportes altos aramados dourados para vasos. 1 Vaso dourado com flores amarelas e brancas. 1 Vaso branco com flores mistas. Arranjo de chao com girassois e rosas. Kit de baloes metalizados dourados. 1 Tapete texturizado bege/ouro. 1 Cachepo de madeira com buxinho. 1 Suporte de bolo aramado dourado.',true,12) returning id into p12;
insert into products(title,price,image,category,description,active,sort_order) values('Kit Festa Sonic Luxo azul e dourado',0,base||'sonic-luxo-azul-dourado.jpeg','Kit Festa','Led com a idade (se disponivel). 3 Cilindros grande, medio e pequeno. 1 Painel redondo. 1 Arco lateral Sonic. 1 Boleira. 9 Bandejas para doces. 1 Suporte para sacolinhas. 1 Mesa principal branca. 1 Tapete vermelho ou azul. 1 Vaso com bola de grama. 2 Arcos organicos de baloes.',true,13) returning id into p13;
insert into products(title,price,image,category,description,active,sort_order) values('Nature Green & Gold',0,base||'nature-green-gold.jpeg','Locacao','Painel de fundo retangular verde musgo. Cortinas laterais de cetim dourado e branco. Arco organico verde folha, verde limao e dourado cromado. Letreiro de neon Happy Birthday em suporte redondo dourado. 3 Mesas cilindricas base aramada dourada (P, M, G). 1 Vaso alto branco com buxinho verde. 1 Vaso de ceramica branco com folhagem. Folha de palmeira seca dourada. 1 Tapete felpudo cinza escuro. 1 Suporte de bolo aramado dourado. 2 Bandejas redondas douradas com espelho.',true,14) returning id into p14;
insert into products(title,price,image,category,description,active,sort_order) values('Passion Red & Gold',0,base||'passion-red-gold.jpeg','Locacao','Painel de fundo arredondado vermelho texturizado. Arco organico vermelho fosco e dourado cromado. Letreiro de neon com o numero desejado. 3 Mesas cilindricas aramadas douradas com tampos vermelhos. 2 Vasos altos de cristal com rosas vermelhas e palmeira dourada. 1 Tapete felpudo vermelho. 1 Suporte de bolo aramado dourado. 4 Bandejas douradas redondas com pe.',true,15) returning id into p15;
insert into products(title,price,image,category,description,active,sort_order) values('Purple & Silver',0,base||'purple-silver.jpeg','Locacao','Painel de fundo arredondado lilas texturizado. Arco organico roxo fosco, lilas e prata cromado. Placa manuscrita com nome personalizado. 3 Mesas cilindricas aramadas douradas com tampos roxos. 1 Suporte alto aramado dourado. 1 Vaso alto lilas com arranjo de rosas. Arranjo floral de chao (rosas brancas, rosa choque e lilas). 1 Tapete texturizado bege/ouro. 1 Suporte de bolo aramado dourado com tampo roxo.',true,16) returning id into p16;
insert into products(title,price,image,category,description,active,sort_order) values('Royal Blue & Gold',0,base||'royal-blue-gold.jpeg','Locacao','Painel de fundo arredondado azul royal texturizado. Arco organico azul royal, azul claro e dourado cromado. Placa dourada com Happy Birthday manuscrita. 3 Cilindros azuis royal (P, M, G). 2 Vasos de metal dourado alto com buxinhos verdes. Placa manuscrita personalizada. 1 Tapete felpudo bege claro/creme. 1 Suporte de bolo dourado. 2 Bandejas retangulares douradas com espelho.',true,17) returning id into p17;
insert into products(title,price,image,category,description,active,sort_order) values('Soft Rose & Gold',0,base||'soft-rose-gold.jpeg','Locacao','Painel de fundo arredondado rosa seco (dusty rose). Arco organico rosa chiclete e branco. Letreiro de neon Happy Birthday. 3 Mesas cilindricas base aramada dourada (P, M, G). 1 Suporte alto aramado dourado. 1 Vaso de metal dourado rose com flores brancas. 1 Vaso de ceramica canelado rosa com flores rosas. Arranjo floral de chao. Kit de baloes metalizados ouro rose. 1 Tapete felpudo rosa claro. 1 Suporte de bolo aramado dourado rose.',true,18) returning id into p18;
insert into products(title,price,image,category,description,active,sort_order) values('Sonic Delux',0,base||'sonic-delux.jpeg','Kit Festa','1 Arco romano Sonic. 1 Painel redondo. 3 Cilindros. 1 Mesa central tamanho medio. 1 Escadinha. Tapete azul. 9 Bandejas para doces. 1 Boleira.',true,19) returning id into p19;
insert into products(title,price,image,category,description,active,sort_order) values('Vibrant Pink & Gold',0,base||'vibrant-pink-gold.jpeg','Locacao','Painel de fundo rosa vibrante. Grande arco organico rosa choque e dourado cromado. Placa Happy Birthday em branco manuscrita. 1 Mesa de cubo dourada com espelho. 1 Cilindro rosa vibrante grande. 1 Boleira aramada dourada. 1 Suporte dourado para doces. 1 Bandeja dourada. Kit de baloes metalizados rosa pink formando o numero. 1 Tapete felpudo rosa claro. 1 Vaso aramado dourado com buxinho verde.',true,20) returning id into p20;
insert into products(title,price,image,category,description,active,sort_order) values('Vibrant Purple',0,base||'vibrant-purple.png','Locacao','Painel de fundo arredondado lilas suave texturizado. 1 Arco organico grande roxo fosco e roxo metalizado. 1 Coluna de baloes lilas. Letreiro de neon Happy Birthday. 3 Mesas de base geometrica aramada dourada (P, M, G). 3 Suportes aramados dourados para doces. 3 Bandejas redondas douradas com espelho. Vasos altos de cristal com arranjo floral roxo misto. 1 Tapete de tecido bege texturizado.',true,21) returning id into p21;
insert into products(title,price,image,category,description,active,sort_order) values('White & Crystal Black Bow',0,base||'white-crystal-black-bow.jpeg','Locacao','Painel de fundo arredondado branco texturizado (estilo marmore). Arco organico de baloes brancos foscos com lacos de fita pretos. Letreiro de neon Happy Birthday. 1 Grande laco de tecido preto no topo. 3 Cilindros brancos texturizados. 2 Vasos de cristal com arranjo floral branco e rosa cha. 1 Tapete felpudo cinza escuro. 2 Suportes de bolo/doces brancos. 2 Pratos pretos e transparentes para doces.',true,22) returning id into p22;
